import json, os, sys
class JSONVeritabaniYoneticisi:
    def __init__(self):
        self.veriler = []
        self.dosya = "json_veritabani_yoneticisi.json"
    def yukle(self):
        if os.path.exists(self.dosya):
            with open(self.dosya, "r", encoding="utf-8") as f: self.veriler = json.load(f)
    def kaydet(self):
        with open(self.dosya, "w", encoding="utf-8") as f: json.dump(self.veriler, f, indent=2, ensure_ascii=False)
    def ekle(self, deger):
        self.veriler.append(deger); self.kaydet(); print(f"Eklendi: {deger}")
    def listele(self):
        for i, v in enumerate(self.veriler, 1): print(f"{i}. {v}")
    def ara(self, kelime):
        sonuc = [v for v in self.veriler if kelime.lower() in str(v).lower()]
        print(f"{len(sonuc)} sonuc:"); [print(f"  - {s}") for s in sonuc]
    def sil(self, index):
        if 0 <= index < len(self.veriler):
            silinen = self.veriler.pop(index); self.kaydet(); print(f"Silindi: {silinen}")
    def menu(self):
        self.yukle()
        while True:
            s = input("\\n1:Ekle 2:Listele 3:Ara 4:Sil 5:Cikis: ")
            if s == "5": break
            elif s == "1": self.ekle(input("Deger: "))
            elif s == "2": self.listele()
            elif s == "3": self.ara(input("Kelime: "))
            elif s == "4": self.sil(int(input("Index: ")) - 1)
if __name__ == "__main__":
    app = JSONVeritabaniYoneticisi()
    app.menu()

