    try { veriler = JSON.parse(fs.readFileSync(dosya, "utf8")); } catch(e) { veriler = []; }
}
function kaydet() { fs.writeFileSync(dosya, JSON.stringify(veriler, null, 2)); }
function ekle(deger) { veriler.push(deger); kaydet(); console.log("Eklendi:", deger); menu(); }
function listele() { veriler.forEach((v, i) => console.log(i+1 + ".", v)); menu(); }
function ara(kelime) {
    const sonuc = veriler.filter(v => v.toLowerCase().includes(kelime.toLowerCase()));
    console.log(sonuc.length + " sonuc:"); sonuc.forEach(s => console.log("  -", s)); menu();
}
function sil(idx) {
    if (idx >= 0 && idx < veriler.length) {
        const silinen = veriler.splice(idx, 1); kaydet(); console.log("Silindi:", silinen[0]);
    } else console.log("Gecersiz index"); menu();
}
function menu() {
    rl.question("\\n1:Ekle 2:Listele 3:Ara 4:Sil 5:Cikis: ", secim => {
        if (secim === "5") return rl.close();
        else if (secim === "1") rl.question("Deger: ", d => { ekle(d); });
        else if (secim === "2") listele();
        else if (secim === "3") rl.question("Kelime: ", k => { ara(k); });
        else if (secim === "4") rl.question("Index: ", i => { sil(parseInt(i)-1); });
        else menu();
    });
}
yukle();
console.log("URL Kodlayici uygulamasi baslatildi.");
menu();

