import java.util.*;
import java.io.*;
public class JSONVeritabaniYoneticisi {
    static List<String> veriler = new ArrayList<>();
    static String dosya = "json_veritabani_yoneticisi.json";
    public static void yukle() throws Exception {
        File f = new File(dosya);
        if (f.exists()) {
            Scanner sc = new Scanner(f); sc.useDelimiter("\\Z");
            String icerik = sc.hasNext() ? sc.next() : ""; sc.close();
            try { veriler = new ArrayList<>(Arrays.asList(new com.google.gson.Gson().fromJson(icerik, String[].class))); }
            catch(Exception e) { veriler = new ArrayList<>(); }
        }
    }
    public static void kaydet() throws Exception {
        try (PrintWriter pw = new PrintWriter(dosya)) {
            pw.println(new com.google.gson.GsonBuilder().setPrettyPrinting().create().toJson(veriler));
        }
    }
    public static void ekle(String deger) throws Exception { veriler.add(deger); kaydet(); System.out.println("Eklendi: " + deger); }
    public static void listele() { for(int i=0;i<veriler.size();i++) System.out.println((i+1) + ". " + veriler.get(i)); }
    public static void sil(int idx) throws Exception {
        if(idx>=0 && idx<veriler.size()) { String s = veriler.remove(idx); kaydet(); System.out.println("Silindi: " + s); }
    }
    public static void main(String[] args) throws Exception {
        yukle(); Scanner sc = new Scanner(System.in);
        while(true) {
            System.out.print("\\n1:Ekle 2:Listele 3:Sil 4:Cikis: ");
            String s = sc.nextLine();
            if(s.equals("4")) break;
            else if(s.equals("1")) { System.out.print("Deger: "); ekle(sc.nextLine()); }
            else if(s.equals("2")) listele();
            else if(s.equals("3")) { System.out.print("Index: "); sil(Integer.parseInt(sc.nextLine())-1); }
        }
    }
}

