package main
import ("encoding/json";"fmt";"io/ioutil";"os";"bufio";"strings")
type App struct { Veriler []string `json:"veriler"` }
var dosya = "json_veritabani_yoneticisi.json"
func yukle() App {
    var app App
    if data, err := ioutil.ReadFile(dosya); err == nil { json.Unmarshal(data, &app) }
    return app
}
func (app *App) kaydet() {
    data, _ := json.MarshalIndent(app, "", "  ")
    ioutil.WriteFile(dosya, data, 0644)
}
func main() {
    app := yukle(); scanner := bufio.NewScanner(os.Stdin)
    fmt.Println("JSONVeritabaniYoneticisi uygulamasi baslatildi.")
    for {
        fmt.Print("\\n1:Ekle 2:Listele 3:Sil 4:Cikis: "); scanner.Scan()
        switch scanner.Text() {
        case "4": return
        case "1": fmt.Print("Deger: "); scanner.Scan(); app.Veriler = append(app.Veriler, scanner.Text()); app.kaydet(); fmt.Println("Eklendi.")
        case "2": for i, v := range app.Veriler { fmt.Printf("%d. %s\\n", i+1, v) }
        case "3": fmt.Print("Index: "); scanner.Scan()
            var idx int; fmt.Sscanf(scanner.Text(), "%d", &idx)
            if idx>0 && idx<=len(app.Veriler) { app.Veriler = append(app.Veriler[:idx-1], app.Veriler[idx:]...); app.kaydet(); fmt.Println("Silindi.") }
        }
    }
}

