const dosya = "http_header_analiz.json";
let veriler: string[] = [];
function yukle(): void {
    try { veriler = JSON.parse(fs.readFileSync(dosya, "utf8")); } catch { veriler = []; }
}
function kaydet(): void { fs.writeFileSync(dosya, JSON.stringify(veriler, null, 2)); }
const rl = readline.createInterface({ input: process.stdin, output: process.stdout });
function sor(q: string): Promise<string> {
    return new Promise(resolve => rl.question(q, resolve));
}
async function menu() {
    while (true) {
        const s = await sor("\\n1:Ekle 2:Listele 3:Sil 4:Cikis: ");
        if (s === "4") break;
        else if (s === "1") { const d = await sor("Deger: "); veriler.push(d); kaydet(); console.log("Eklendi."); }
        else if (s === "2") { veriler.forEach((v, i) => console.log(i+1 + ".", v)); }
        else if (s === "3") { const idx = parseInt(await sor("Index: ")) - 1; if(idx>=0 && idx<veriler.length) { veriler.splice(idx,1); kaydet(); console.log("Silindi."); } }
    }
    rl.close();
}
yukle(); console.log("HTTP Header Analiz uygulamasi baslatildi."); menu();

